import{_ as e,a as o,b as r}from"./chunks/配置容量限制.DkdWbdOw.js";import{_ as t,o as d,c as i,a2 as c}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Adicionar canal Cloudflare R2","description":"","frontmatter":{},"headers":[],"relativePath":"pt-BR/upload/cloudflare-r2.md","filePath":"pt-BR/upload/cloudflare-r2.md","lastUpdated":1781962217000}'),l={name:"pt-BR/upload/cloudflare-r2.md"};function n(u,a,s,p,m,h){return d(),i("div",null,[...a[0]||(a[0]=[c('<h1 id="adicionar-canal-cloudflare-r2" tabindex="-1">Adicionar canal Cloudflare R2 <a class="header-anchor" href="#adicionar-canal-cloudflare-r2" aria-label="Permalink to &quot;Adicionar canal Cloudflare R2&quot;">​</a></h1><p>O canal Cloudflare R2 salva arquivos em um bucket R2.</p><h2 id="quando-usar" tabindex="-1">Quando usar <a class="header-anchor" href="#quando-usar" aria-label="Permalink to &quot;Quando usar&quot;">​</a></h2><ul><li>Você quer gerenciar armazenamento dentro do ecossistema Cloudflare.</li><li>Vai usar R2 como destino principal do ImgBed.</li><li>Quer combinar R2 com domínio personalizado ou CDN.</li></ul><h2 id="o-que-preparar" tabindex="-1">O que preparar <a class="header-anchor" href="#o-que-preparar" aria-label="Permalink to &quot;O que preparar&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Item</th><th>Uso</th></tr></thead><tbody><tr><td>Conta Cloudflare</td><td>Gerenciar R2 e tokens</td></tr><tr><td>Bucket R2</td><td>Destino real dos arquivos</td></tr><tr><td>Account ID</td><td>Identificar a conta</td></tr><tr><td>API Token</td><td>Permitir leitura e escrita no R2</td></tr><tr><td>Domínio personalizado</td><td>Opcional, para URLs públicas mais limpas</td></tr></tbody></table><h2 id="criar-o-bucket" tabindex="-1">Criar o bucket <a class="header-anchor" href="#criar-o-bucket" aria-label="Permalink to &quot;Criar o bucket&quot;">​</a></h2><p>No Cloudflare Dashboard, abra <code>R2 Object Storage</code> e crie um bucket.</p><p><img src="'+e+'" alt="Criar bucket R2" loading="lazy"></p><p>Guarde o nome exato do bucket, pois ele deve ser informado igual no ImgBed.</p><h2 id="encontrar-o-account-id" tabindex="-1">Encontrar o Account ID <a class="header-anchor" href="#encontrar-o-account-id" aria-label="Permalink to &quot;Encontrar o Account ID&quot;">​</a></h2><p>Na página da conta Cloudflare, veja o Account ID.</p><p><img src="'+o+'" alt="Account ID" loading="lazy"></p><h2 id="preencher-no-imgbed" tabindex="-1">Preencher no ImgBed <a class="header-anchor" href="#preencher-no-imgbed" aria-label="Permalink to &quot;Preencher no ImgBed&quot;">​</a></h2><p>Em Configurações de upload, abra <code>Adicionar canal</code> e escolha <code>Cloudflare R2</code>.</p><table tabindex="0"><thead><tr><th>Campo</th><th>Valor</th></tr></thead><tbody><tr><td>Nome do canal</td><td>Nome fácil de reconhecer</td></tr><tr><td>Account ID</td><td>Account ID da Cloudflare</td></tr><tr><td>Bucket</td><td>Nome do bucket R2</td></tr><tr><td>API Token</td><td>Token com permissão no R2</td></tr><tr><td>Domínio personalizado</td><td>Opcional</td></tr><tr><td>Diretório</td><td>Opcional; normalmente <code>imgbed</code></td></tr></tbody></table><h2 id="limite-de-capacidade" tabindex="-1">Limite de capacidade <a class="header-anchor" href="#limite-de-capacidade" aria-label="Permalink to &quot;Limite de capacidade&quot;">​</a></h2><p>Você pode ativar limite de capacidade para controlar quando esse canal deixa de ser usado.</p><p><img src="'+r+'" alt="Limite de capacidade" loading="lazy"></p><p>Quando o uso chega ao limite configurado, o ImgBed pode deixar de selecionar esse canal para novos uploads.</p><h2 id="verificacao" tabindex="-1">Verificação <a class="header-anchor" href="#verificacao" aria-label="Permalink to &quot;Verificação&quot;">​</a></h2><ol><li>O cartão do canal R2 aparece após salvar.</li><li>O canal está habilitado.</li><li>Envie uma imagem de teste.</li><li>Confira se o objeto aparece no bucket.</li><li>Abra o link retornado pelo ImgBed.</li></ol><h2 id="erros-comuns" tabindex="-1">Erros comuns <a class="header-anchor" href="#erros-comuns" aria-label="Permalink to &quot;Erros comuns&quot;">​</a></h2><ul><li>Account ID ou nome do bucket incorreto.</li><li>Token sem permissões suficientes no bucket.</li><li>Domínio personalizado não conectado ao bucket.</li><li>Canal fora da seleção por limite de capacidade.</li></ul>',24)])])}const q=t(l,[["render",n]]);export{k as __pageData,q as default};
